        std::vector<art::ArtField> fields;
        Android::ForeachInstanceField(super, callback);

        for (auto& field : fields) {
            if (field.GetTypeDescriptor() == "L...") {  // 只检查对象引用字段
                art::mirror::Object tmp(field.GetObj(object));
                if (tmp.Ptr() && !tmp.IsValid()) {
                    LOGE("Instance [%p] field %s is bad", object.Ptr(), field.GetName());
                }
            }
        }
        super = super.GetSuperClass();  // 向上遍历父类
    } while (super.Ptr());
}
